const { pedidos } = $input.first().json;

const ahora = new Date();
const ahoraCO = new Date(ahora.toLocaleString('en-US', { timeZone: 'America/Bogota' }));

// Semana anterior: lunes a domingo
const lunesAnterior = new Date(ahoraCO);
lunesAnterior.setDate(ahoraCO.getDate() - 7);
lunesAnterior.setHours(0,0,0,0);
const domingoAnterior = new Date(lunesAnterior);
domingoAnterior.setDate(lunesAnterior.getDate() + 6);
domingoAnterior.setHours(23,59,59,999);

// Pedidos activos (no enviado-final)
const activos = pedidos.filter(p => p.estado !== 'enviado-final');

// Entregados esta semana
const entregados = pedidos.filter(p =>
  p.estado === 'enviado-final' &&
  p.ultimoMovimiento &&
  new Date(p.ultimoMovimiento) >= lunesAnterior &&
  new Date(p.ultimoMovimiento) <= domingoAnterior
);

// Por estado
const etiquetas = {
  'bandeja': '🗂 Bandeja', 'hacer-diseno': '🎨 Diseño', 'confirmado': '✅ Confirmado',
  'enviado-calandra': '🖨 Calandra', 'llego-impresion': '🖨 Impresión', 'corte': '✂️ Corte',
  'calidad': '🔍 Calidad', 'costura': '🧵 Costura', 'listo': '📦 Listo'
};
const conteos = {};
Object.keys(etiquetas).forEach(e => conteos[e] = 0);
activos.forEach(p => { if (conteos[p.estado] !== undefined) conteos[p.estado]++; });
const lineasEstados = Object.entries(etiquetas)
  .filter(([k]) => conteos[k] > 0)
  .map(([k, label]) => `  ${label}: ${conteos[k]}`)
  .join('\n');

// Sin movimiento +3 días
const sinMovimiento = activos.filter(p => {
  const ref = p.ultimoMovimiento || p.ultimaActWebhook || null;
  if (!ref) return false;
  return (ahora - new Date(ref)) / (1000*60*60*24) >= 3;
});
const listaSinMov = sinMovimiento.slice(0, 5).map(p => {
  const dias = Math.floor((ahora - new Date(p.ultimoMovimiento || p.ultimaActWebhook)) / (1000*60*60*24));
  return `  • #${p.id} ${p.equipo || p.telefono || '?'} — ${p.estado} (${dias}d)`;
}).join('\n');
const massinmov = sinMovimiento.length > 5 ? `\n  ...y ${sinMovimiento.length - 5} más` : '';

// Vencidos
const vencidos = activos.filter(p => {
  if (!p.fechaEntrega) return false;
  const [d,m,y] = p.fechaEntrega.split('/');
  return new Date(+y, +m-1, +d) < ahoraCO;
});
const listaVencidos = vencidos.slice(0, 5).map(p => {
  const [d,m,y] = p.fechaEntrega.split('/');
  const dias = Math.round((ahoraCO - new Date(+y,+m-1,+d)) / (1000*60*60*24));
  return `  • #${p.id} ${p.equipo || p.telefono || '?'} — hace ${dias}d (${p.estado})`;
}).join('\n');
const masvenc = vencidos.length > 5 ? `\n  ...y ${vencidos.length - 5} más` : '';

const fechaIni = lunesAnterior.toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });
const fechaFin = domingoAnterior.toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });

const texto = `📊 *Reporte Semanal — W&S Textil*
📅 Semana ${fechaIni} → ${fechaFin}

✅ *Entregados:* ${entregados.length}  |  📦 *Activos:* ${activos.length}

📋 *Por etapa:*
${lineasEstados || '  Sin datos'}

⚠️ *Sin movimiento +3d:* ${sinMovimiento.length}
${sinMovimiento.length ? listaSinMov + massinmov : '  Ninguno 👍'}

🔴 *Vencidos:* ${vencidos.length}
${vencidos.length ? listaVencidos + masvenc : '  Ninguno 👍'}`;

return [{ json: { texto } }];
